from flask import Blueprint, request, jsonify, g

from middleware import get_current_user, check_permission, get_user_permissions
from app import db
from models import Role, Permission, User, role_permissions, user_roles

role_bp = Blueprint('role_bp', __name__)


def _has_cycle(role_id, target_parent_id):
    """Check if setting role_id's parent to target_parent_id would create a cycle."""
    visited = set()
    current = target_parent_id
    while current is not None:
        if current == role_id:
            return True
        if current in visited:
            return False
        visited.add(current)
        role = Role.query.get(current)
        if role is None:
            return False
        current = role.parent_role_id
    return False


def _serialize_role(role):
    """Serialize a role with its permission codes."""
    return {
        'id': role.id,
        'name': role.name,
        'tenant_id': role.tenant_id,
        'parent_role_id': role.parent_role_id,
        'permissions': [p.code for p in role.permissions],
    }


@role_bp.route('/roles', methods=['GET'])
@check_permission('role.manage')
def list_roles():
    """List roles for the current user's tenant."""
    user = g.current_user
    roles = Role.query.filter_by(tenant_id=user.tenant_id).all()
    return jsonify({'status': 'ok', 'data': [_serialize_role(r) for r in roles]}), 200


@role_bp.route('/roles', methods=['POST'])
@check_permission('role.manage')
def create_role():
    """Create a new role within the current tenant."""
    user = g.current_user
    data = request.get_json(silent=True) or {}

    name = data.get('name')
    if not name:
        return jsonify({'status': 'error', 'message': 'Missing role name'}), 400

    # Check duplicate name within same tenant
    existing = Role.query.filter_by(tenant_id=user.tenant_id, name=name).first()
    if existing:
        return jsonify({'status': 'error', 'message': 'Role already exists'}), 409

    perm_codes = data.get('permissions', [])
    parent_role_id = data.get('parent_role_id')

    # Validate parent belongs to same tenant
    if parent_role_id is not None:
        parent = Role.query.get(parent_role_id)
        if parent is None or parent.tenant_id != user.tenant_id:
            return jsonify({'status': 'error', 'message': 'Invalid parent role'}), 400

    # Check for cycle if parent_role_id is set
    role = Role(
        tenant_id=user.tenant_id,
        name=name,
        parent_role_id=parent_role_id,
    )
    db.session.add(role)
    db.session.flush()  # Get the role ID for cycle check

    if parent_role_id is not None and _has_cycle(role.id, parent_role_id):
        db.session.rollback()
        return jsonify({'status': 'error', 'message': 'Role inheritance cycle detected'}), 400

    # Assign permissions
    for code in perm_codes:
        perm = Permission.query.filter_by(code=code).first()
        if perm:
            role.permissions.append(perm)

    db.session.commit()
    return jsonify({'status': 'ok', 'data': _serialize_role(role)}), 201


@role_bp.route('/roles/<int:role_id>/permissions', methods=['PUT'])
@check_permission('role.manage')
def update_role_permissions(role_id):
    """Update role permissions and/or parent role."""
    user = g.current_user
    data = request.get_json(silent=True) or {}

    role = Role.query.get(role_id)
    if role is None or role.tenant_id != user.tenant_id:
        return jsonify({'status': 'error', 'message': 'Role not found'}), 404

    perm_codes = data.get('permissions', [])
    parent_role_id = data.get('parent_role_id', role.parent_role_id)

    # Validate parent belongs to same tenant
    if parent_role_id is not None:
        parent = Role.query.get(parent_role_id)
        if parent is None or parent.tenant_id != user.tenant_id:
            return jsonify({'status': 'error', 'message': 'Invalid parent role'}), 400

    # Check for cycle
    if parent_role_id is not None and _has_cycle(role.id, parent_role_id):
        return jsonify({'status': 'error', 'message': 'Role inheritance cycle detected'}), 400

    # Update parent
    role.parent_role_id = parent_role_id

    # Replace permissions
    role.permissions = []
    for code in perm_codes:
        perm = Permission.query.filter_by(code=code).first()
        if perm:
            role.permissions.append(perm)

    db.session.commit()
    return jsonify({'status': 'ok', 'data': _serialize_role(role)}), 200


@role_bp.route('/users/<int:user_id>/roles', methods=['POST'])
@check_permission('role.manage')
def assign_role(user_id):
    """Assign a role to a user. Both must belong to the same tenant."""
    current = g.current_user
    data = request.get_json(silent=True) or {}
    role_id = data.get('role_id')

    target_user = User.query.get(user_id)
    if target_user is None or target_user.tenant_id != current.tenant_id:
        return jsonify({'status': 'error', 'message': 'User not found'}), 404

    role = Role.query.get(role_id)
    if role is None or role.tenant_id != current.tenant_id:
        return jsonify({'status': 'error', 'message': 'Role not found'}), 404

    db.session.execute(user_roles.insert().values(user_id=user_id, role_id=role_id))
    db.session.commit()

    return jsonify({'status': 'ok', 'data': None}), 200


@role_bp.route('/users/<int:user_id>/roles/<int:role_id>', methods=['DELETE'])
@check_permission('role.manage')
def remove_role(user_id, role_id):
    """Remove a role from a user. Idempotent."""
    current = g.current_user

    target_user = User.query.get(user_id)
    if target_user is None or target_user.tenant_id != current.tenant_id:
        return jsonify({'status': 'error', 'message': 'User not found'}), 404

    db.session.execute(user_roles.delete().where(
        (user_roles.c.user_id == user_id) & (user_roles.c.role_id == role_id)
    ))
    db.session.commit()

    return jsonify({'status': 'ok', 'data': None}), 200

